const user = $('Split per user').item.json;
const events = Array.isArray($input.first().json) ? $input.first().json : ($input.first().json.data || []);
const total = events.length;
const counts = { resisted: 0, breathed: 0, contacted: 0, relapsed: 0, dismissed: 0 };
for (const e of events) {
  if (counts[e.outcome] !== undefined) counts[e.outcome]++;
}
const topMoodMap = {};
for (const e of events) if (e.mood) topMoodMap[e.mood] = (topMoodMap[e.mood] || 0) + 1;
const topMood = Object.entries(topMoodMap).sort((a,b)=>b[1]-a[1])[0]?.[0] || 'sin datos';

const greeting = user.display_name ? `Hola ${user.display_name}` : 'Hola';
const aliado = user.aliado_name || 'Aliado';

const html = `<!doctype html><html><body style="font-family:system-ui,sans-serif;line-height:1.5;color:#222;max-width:520px;margin:0 auto;padding:24px">
  <h2 style="margin:0 0 8px">${greeting},</h2>
  <p>Soy ${aliado}. Esta es tu semana, sin juicio, solo lo que paso.</p>
  <ul>
    <li><b>${total}</b> momentos en los que la app estuvo contigo.</li>
    <li><b>${counts.resisted + counts.breathed + counts.contacted}</b> veces saliste sin caer.</li>
    <li><b>${counts.relapsed}</b> veces caiste. No es el fin del mundo, es informacion.</li>
    <li>Estado emocional mas frecuente esta semana: <b>${topMood}</b>.</li>
  </ul>
  <p>Empezamos otra semana mañana. Yo sigo aqui.</p>
  <p style="font-size:12px;color:#888;margin-top:32px">Antiport · privado y gratuito · <a href="https://antiport.app/ajustes/email">ajustar avisos</a></p>
</body></html>`;

const text = `${greeting},\n\nEsta semana: ${total} momentos contigo, ${counts.resisted + counts.breathed + counts.contacted} sin caer, ${counts.relapsed} caidas. Estado mas frecuente: ${topMood}.\n\nManana empezamos otra. Sigo aqui.\n\n— ${aliado}`;

return [{ json: { ...user, html, text, subject: 'Tu semana en Antiport' } }];
